# Programmatically expand packs to 40 unique cards (mass-market) or 30 unique cards (luxury/specialty)
for pack_name, extra_list in extra_cars_definitions.items():
    if pack_name in pack_cars:
        pack_cars[pack_name].extend(extra_list)

formatted_cards = []
for pack_name, cars in pack_cars.items():
    total_cards_in_pack = len(cars)
    ticker = pack_tickers.get(pack_name, "CARD")
    for idx, car in enumerate(cars):
        set_index_str = f"{idx + 1:02d}/{total_cards_in_pack:02d}"
        card_obj = {
            "id": car["id"],
            "manufacturer": car["manufacturer"],
            "name": car["name"],
            "pack_eligibility": [pack_name], # Zero repetition! Assigned to exactly 1 pack.
            "rarity": car["rarity"],
            "stats": car["stats"],
            "ovr": 0,
            "discovered": False,
            "set_index": set_index_str,
            "set_name": ticker
        }
        formatted_cards.append(card_obj)

